<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { width: 100%; height: 100%; overflow: hidden; font-family: 'Ubuntu', 'Segoe UI', 'Helvetica Neue', Arial, sans-serif; }

  /* ── Desktop ── */
  #desktop {
    position: fixed; inset: 0;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 40%, #0f3460 100%);
    display: flex; flex-direction: column;
    user-select: none;
  }

  /* ── Top Bar ── */
  #topbar {
    height: 28px; background: #1a1a1a; color: #ddd;
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 12px; font-size: 13px; z-index: 100;
    box-shadow: 0 1px 3px rgba(0,0,0,.5);
  }
  #topbar .left { display: flex; align-items: center; gap: 14px; }
  #topbar .left .app-name { font-weight: 600; color: #e95420; letter-spacing: .5px; }
  #topbar .right { display: flex; align-items: center; gap: 10px; font-size: 12px; color: #aaa; }

  /* ── Taskbar / Dock ── */
  #taskbar {
    position: absolute; bottom: 0; left: 0; right: 0;
    height: 52px; background: rgba(20,20,20,.92);
    display: flex; align-items: center; justify-content: center; gap: 8px;
    z-index: 100; backdrop-filter: blur(6px);
    border-top: 1px solid rgba(255,255,255,.08);
  }
  .dock-btn {
    width: 42px; height: 42px; border-radius: 10px; border: none;
    cursor: pointer; display: flex; align-items: center; justify-content: center;
    transition: transform .15s, box-shadow .15s;
    position: relative;
  }
  .dock-btn:hover { transform: scale(1.12); box-shadow: 0 4px 14px rgba(0,0,0,.45); }
  .dock-btn:active { transform: scale(.97); }
  .dock-btn svg { width: 26px; height: 26px; }
  .dock-btn .dot {
    position: absolute; bottom: -4px; width: 5px; height: 5px;
    border-radius: 50%; background: #e95420; opacity: 0; transition: opacity .2s;
  }
  .dock-btn.active .dot { opacity: 1; }

  /* ── Windows ── */
  .app-window {
    position: absolute; min-width: 360px; min-height: 240px;
    background: #2d2d2d; border-radius: 10px;
    box-shadow: 0 8px 32px rgba(0,0,0,.55), 0 0 0 1px rgba(255,255,255,.06);
    display: none; flex-direction: column; overflow: hidden;
    z-index: 50;
  }
  .app-window.visible { display: flex; }
  .win-titlebar {
    height: 36px; background: #1e1e1e; display: flex; align-items: center;
    padding: 0 10px; cursor: grab; flex-shrink: 0;
    border-bottom: 1px solid #333;
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-titlebar .title { flex: 1; text-align: center; color: #ccc; font-size: 13px; font-weight: 500; }
  .win-close {
    width: 28px; height: 28px; border-radius: 50%; border: none;
    background: #e95420; color: #fff; font-size: 15px; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: background .15s;
  }
  .win-close:hover { background: #c7431b; }

  /* ── Files App ── */
  #files-window { width: 640px; height: 440px; top: 60px; left: 80px; }
  .files-toolbar {
    display: flex; align-items: center; gap: 8px; padding: 6px 10px;
    background: #252525; border-bottom: 1px solid #3a3a3a;
  }
  #files-up {
    width: 30px; height: 30px; border-radius: 6px; border: none;
    background: #3a3a3a; color: #ccc; cursor: pointer; font-size: 16px;
    display: flex; align-items: center; justify-content: center;
  }
  #files-up:hover { background: #4a4a4a; }
  #files-path {
    flex: 1; background: #1a1a1a; border: 1px solid #444; border-radius: 6px;
    padding: 4px 10px; color: #e95420; font-size: 13px; font-family: monospace;
    outline: none;
  }
  #files-path:focus { border-color: #e95420; }
  .files-body { flex: 1; padding: 12px; overflow-y: auto; display: flex; flex-wrap: wrap; gap: 10px; align-content: flex-start; }
  .fs-item {
    width: 90px; display: flex; flex-direction: column; align-items: center;
    padding: 8px 4px; border-radius: 8px; cursor: pointer; transition: background .12s;
  }
  .fs-item:hover { background: rgba(255,255,255,.07); }
  .fs-item .icon { font-size: 36px; margin-bottom: 4px; line-height: 1; }
  .fs-item .name { font-size: 11px; color: #ddd; text-align: center; word-break: break-all; }
  .fs-item.folder .icon { color: #e95420; }
  .fs-item.file .icon { color: #7eb8e0; }

  /* ── Notepad App ── */
  #notepad-window { width: 580px; height: 420px; top: 80px; left: 200px; }
  .notepad-toolbar {
    display: flex; align-items: center; gap: 6px; padding: 4px 8px;
    background: #252525; border-bottom: 1px solid #3a3a3a;
  }
  #new-tab {
    height: 28px; padding: 0 10px; border-radius: 5px; border: none;
    background: #e95420; color: #fff; font-size: 13px; cursor: pointer;
    font-weight: 600;
  }
  #new-tab:hover { background: #c7431b; }
  #tabs {
    flex: 1; display: flex; align-items: stretch; gap: 2px;
    overflow-x: auto; padding: 0 4px;
  }
  .tab {
    padding: 4px 14px; border-radius: 6px 6px 0 0; cursor: pointer;
    background: #1e1e1e; color: #999; font-size: 12px; white-space: nowrap;
    border: 1px solid transparent; border-bottom: none;
    display: flex; align-items: center; gap: 6px;
    transition: background .12s, color .12s;
  }
  .tab:hover { background: #2a2a2a; color: #ccc; }
  .tab.active { background: #2d2d2d; color: #e95420; border-color: #3a3a3a; }
  .tab .close-tab {
    width: 16px; height: 16px; border-radius: 50%; border: none;
    background: transparent; color: #888; font-size: 12px; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
  }
  .tab .close-tab:hover { background: rgba(255,255,255,.15); color: #fff; }
  #editor {
    flex: 1; background: #1e1e1e; color: #d4d4d4; border: none;
    padding: 12px; font-family: 'Ubuntu Mono', 'Fira Code', 'Consolas', monospace;
    font-size: 14px; resize: none; outline: none; line-height: 1.6;
  }
</style>
</head>
<body>

<div id="desktop">

  <!-- Top Bar -->
  <div id="topbar">
    <div class="left">
      <span class="app-name">Ubuntu</span>
    </div>
    <div class="right">
      <span id="clock"></span>
    </div>
  </div>

  <!-- Windows -->
  <div id="files-window" class="app-window">
    <div class="win-titlebar" data-drag="files-window">
      <span class="title">Files</span>
      <button class="win-close" aria-label="Close">✕</button>
    </div>
    <div class="files-toolbar">
      <button id="files-up" title="Up">↑</button>
      <input id="files-path" value="/" readonly>
    </div>
    <div class="files-body" id="files-body"></div>
  </div>

  <div id="notepad-window" class="app-window">
    <div class="win-titlebar" data-drag="notepad-window">
      <span class="title">Text Editor</span>
      <button class="win-close" aria-label="Close">✕</button>
    </div>
    <div class="notepad-toolbar">
      <button id="new-tab">+ New Tab</button>
      <div id="tabs"></div>
    </div>
    <textarea id="editor" spellcheck="false"></textarea>
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button id="open-files" class="dock-btn" title="Files">
      <svg viewBox="0 0 24 24" fill="none" stroke="#e95420" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/>
      </svg>
      <span class="dot"></span>
    </button>
    <button id="open-notepad" class="dock-btn" title="Text Editor">
      <svg viewBox="0 0 24 24" fill="none" stroke="#7eb8e0" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
        <polyline points="14 2 14 8 20 8"/>
        <line x1="16" y1="13" x2="8" y2="13"/>
        <line x1="16" y1="17" x2="8" y2="17"/>
      </svg>
      <span class="dot"></span>
    </button>
  </div>
</div>

<script>
(function() {
  /* ── Clock ── */
  const clockEl = document.getElementById('clock');
  function updateClock() {
    const d = new Date();
    clockEl.textContent = d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 30000);

  /* ── Filesystem Data ── */
  const filesystem = {
    '/': { type: 'dir', children: ['bin', 'etc', 'home', 'usr', 'var'] },
    '/bin': { type: 'dir', children: ['bash', 'ls', 'cat', 'cp', 'mv', 'rm'] },
    '/etc': { type: 'dir', children: ['passwd', 'hostname', 'fstab', 'ssh'] },
    '/etc/ssh': { type: 'dir', children: ['sshd_config', 'ssh_config'] },
    '/home': { type: 'dir', children: ['user'] },
    '/home/user': { type: 'dir', children: ['Documents', 'Downloads', 'Pictures', '.bashrc', '.profile'] },
    '/home/user/Documents': { type: 'dir', children: ['notes.txt', 'todo.md'] },
    '/home/user/Downloads': { type: 'dir', children: ['archive.tar.gz', 'setup.deb'] },
    '/home/user/Pictures': { type: 'dir', children: ['wallpaper.png', 'screenshot.png'] },
    '/usr': { type: 'dir', children: ['bin', 'lib', 'share'] },
    '/usr/bin': { type: 'dir', children: ['python3', 'gcc', 'make'] },
    '/usr/lib': { type: 'dir', children: ['libc.so', 'libssl.so'] },
    '/usr/share': { type: 'dir', children: ['doc', 'man', 'locale'] },
    '/var': { type: 'dir', children: ['log', 'tmp', 'cache'] },
    '/var/log': { type: 'dir', children: ['syslog', 'auth.log'] },
    '/var/tmp': { type: 'dir', children: [] },
    '/var/cache': { type: 'dir', children: ['apt'] },
  };

  // Add some fake files
  filesystem['/home/user/Documents/notes.txt'] = { type: 'file', content: 'Welcome to Ubuntu!\nThis is a simple text editor.' };
  filesystem['/home/user/Documents/todo.md'] = { type: 'file', content: '# Todo\n- [x] Build desktop\n- [ ] Add more features' };
  filesystem['/home/user/.bashrc'] = { type: 'file', content: '# ~/.bashrc\nexport PATH=$PATH:/usr/local/bin' };
  filesystem['/home/user/.profile'] = { type: 'file', content: '# ~/.profile\nexport LANG=en_US.UTF-8' };
  filesystem['/etc/passwd'] = { type: 'file', content: 'root:x:0:0:root:/root:/bin/bash\nuser:x:1000:1000:User:/home/user:/bin/bash' };
  filesystem['/etc/hostname'] = { type: 'file', content: 'ubuntu-desktop' };
  filesystem['/etc/fstab'] = { type: 'file', content: '# /etc/fstab\n/dev/sda1 / ext4 defaults 0 1' };
  filesystem['/etc/ssh/sshd_config'] = { type: 'file', content: 'Port 22\nPermitRootLogin no' };
  filesystem['/etc/ssh/ssh_config'] = { type: 'file', content: 'Host *\n  ForwardAgent yes' };
  filesystem['/home/user/Downloads/archive.tar.gz'] = { type: 'file', content: '' };
  filesystem['/home/user/Downloads/setup.deb'] = { type: 'file', content: '' };
  filesystem['/home/user/Pictures/wallpaper.png'] = { type: 'file', content: '' };
  filesystem['/home/user/Pictures/screenshot.png'] = { type: 'file', content: '' };
  filesystem['/var/log/syslog'] = { type: 'file', content: '[Jan 1 00:00:00] System started\n[Jan 1 00:00:01] Services loaded' };
  filesystem['/var/log/auth.log'] = { type: 'file', content: '[Jan 1 00:00:00] sshd: Server listening on 0.0.0.0 port 22' };

  /* ── Files App ── */
  let currentPath = '/';
  const filesWindow = document.getElementById('files-window');
  const filesPath = document.getElementById('files-path');
  const filesBody = document.getElementById('files-body');
  const filesUp = document.getElementById('files-up');

  function getEntry(path) { return filesystem[path]; }

  function renderFiles() {
    const entry = getEntry(currentPath);
    if (!entry || entry.type !== 'dir') { filesBody.innerHTML = '<p style="color:#888">Not a directory</p>'; return; }
    filesPath.value = currentPath;
    filesBody.innerHTML = '';
    const children = entry.children || [];
    // Sort: dirs first, then files
    const sorted = children.sort((a, b) => {
      const aDir = getEntry(currentPath === '/' ? '/' + a : currentPath + '/' + a).type === 'dir';
      const bDir = getEntry(currentPath === '/' ? '/' + b : currentPath + '/' + b).type === 'dir';
      if (aDir && !bDir) return -1;
      if (!aDir && bDir) return 1;
      return a.localeCompare(b);
    });
    sorted.forEach(name => {
      const fullPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
      const isDir = getEntry(fullPath).type === 'dir';
      const item = document.createElement('div');
      item.className = 'fs-item ' + (isDir ? 'folder' : 'file');
      item.innerHTML = '<span class="icon">' + (isDir ? '📁' : '📄') + '</span><span class="name">' + name + '</span>';
      item.addEventListener('dblclick', () => {
        if (isDir) {
          currentPath = fullPath;
          renderFiles();
        }
      });
      filesBody.appendChild(item);
    });
  }

  filesUp.addEventListener('click', () => {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/') || '/';
    renderFiles();
  });

  /* ── Notepad App ── */
  const STORAGE_KEY = 'ubuntu-notepad-tabs';
  let tabs = [];
  let activeTabId = null;

  function loadTabs() {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (data) {
        const parsed = JSON.parse(data);
        tabs = parsed.tabs || [];
        activeTabId = parsed.activeTabId || (tabs.length > 0 ? tabs[0].id : null);
      }
    } catch(e) { tabs = []; activeTabId = null; }
    if (!activeTabId || !tabs.find(t => t.id === activeTabId)) {
      if (tabs.length > 0) activeTabId = tabs[0].id;
      else { activeTabId = null; }
    }
  }

  function saveTabs() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ tabs, activeTabId }));
    } catch(e) {}
  }

  function createTab() {
    const id = 'tab-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
    tabs.push({ id, name: 'Untitled', content: '' });
    activeTabId = id;
    saveTabs();
    renderTabs();
    renderEditor();
  }

  function renderTabs() {
    const tabsEl = document.getElementById('tabs');
    tabsEl.innerHTML = '';
    tabs.forEach(tab => {
      const el = document.createElement('div');
      el.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
      el.innerHTML = '<span class="tab-name">' + escapeHtml(tab.name) + '</span><button class="close-tab" data-tab-id="' + tab.id + '" title="Close">✕</button>';
      el.addEventListener('click', (e) => {
        if (e.target.classList.contains('close-tab')) {
          closeTab(tab.id);
          return;
        }
        activeTabId = tab.id;
        saveTabs();
        renderTabs();
        renderEditor();
      });
      tabsEl.appendChild(el);
    });
  }

  function closeTab(id) {
    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;
    tabs.splice(idx, 1);
    if (activeTabId === id) {
      activeTabId = tabs.length > 0 ? tabs[Math.min(idx, tabs.length - 1)].id : null;
    }
    saveTabs();
    renderTabs();
    renderEditor();
  }

  function renderEditor() {
    const editor = document.getElementById('editor');
    const tab = tabs.find(t => t.id === activeTabId);
    if (tab) {
      editor.value = tab.content;
    } else {
      editor.value = '';
    }
  }

  function escapeHtml(str) {
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  document.getElementById('editor').addEventListener('input', function() {
    const tab = tabs.find(t => t.id === activeTabId);
    if (tab) {
      tab.content = this.value;
      saveTabs();
    }
  });

  document.getElementById('new-tab').addEventListener('click', createTab);

  /* ── Window Management ── */
  const filesBtn = document.getElementById('open-files');
  const notepadBtn = document.getElementById('open-notepad');

  function showWindow(win, btn) {
    win.classList.add('visible');
    btn.classList.add('active');
  }
  function hideWindow(win, btn) {
    win.classList.remove('visible');
    btn.classList.remove('active');
  }

  filesBtn.addEventListener('click', () => {
    if (filesWindow.classList.contains('visible')) {
      hideWindow(filesWindow, filesBtn);
    } else {
      showWindow(filesWindow, filesBtn);
      renderFiles();
    }
  });

  notepadBtn.addEventListener('click', () => {
    if (notepadWindow.classList.contains('visible')) {
      hideWindow(notepadWindow, notepadBtn);
    } else {
      showWindow(notepadWindow, notepadBtn);
      renderTabs();
      renderEditor();
    }
  });

  // Close buttons
  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', function() {
      const win = this.closest('.app-window');
      if (win.id === 'files-window') hideWindow(win, filesBtn);
      else if (win.id === 'notepad-window') hideWindow(win, notepadBtn);
    });
  });

  /* ── Draggable Windows ── */
  document.querySelectorAll('.win-titlebar[data-drag]').forEach(tb => {
    let startX, startY, origX, origY, dragging = false;
    const winId = tb.getAttribute('data-drag');
    const win = document.getElementById(winId);

    tb.addEventListener('mousedown', (e) => {
      if (e.target.classList.contains('win-close')) return;
      dragging = true;
      startX = e.clientX;
      startY = e.clientY;
      origX = win.offsetLeft;
      origY = win.offsetTop;
      win.style.zIndex = 60;
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
      e.preventDefault();
    });

    function onMove(e) {
      if (!dragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      win.style.left = (origX + dx) + 'px';
      win.style.top = (origY + dy) + 'px';
    }

    function onUp() {
      dragging = false;
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    }
  });

  /* ── Init Notepad ── */
  loadTabs();
  if (tabs.length === 0) createTab();
  renderTabs();
  renderEditor();

})();
</script>
</body>
</html>
